import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"AI 客诉与风控体系","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/ai-complaint-risk.md","filePath":"projects/liduoxing/ai-complaint-risk.md"}'),i={name:"projects/liduoxing/ai-complaint-risk.md"};function l(n,t,s,h,o,p){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="ai-客诉与风控体系" tabindex="-1">AI 客诉与风控体系 <a class="header-anchor" href="#ai-客诉与风控体系" aria-label="Permalink to &quot;AI 客诉与风控体系&quot;">​</a></h1><blockquote><p>AI 客诉与风控体系是面向金融服务风险识别的项目。它希望把公域舆情、客户反馈、企微聊天、服务过程和历史外诉复盘转成可识别、可分级、可触达、可复盘的风险闭环，让客诉从事后处理前移到 <span class="text-highlight-blue">风险信号识别和前置干预</span>。</p></blockquote><div class="project-snapshot"><div><strong>10 类风险场景</strong><span>退费、服务态度、承诺不符、不合格投资者、代维等</span></div><div><strong>百件级复盘</strong><span>基于多月外诉案例做语义和场景归因</span></div><div><strong>关键词体系</strong><span>年龄、借贷、疾病、保本、投诉、曝光等风险信号</span></div><div><strong>闭环流程</strong><span>识别、匹配、分级、触达、处置、复盘</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>金融服务中的客诉风险通常不会突然出现。很多风险在正式投诉之前，已经出现在客户评论、企微聊天、服务记录、退费诉求、外部平台曝光或内部流程异常中。</p><p>如果只能等客户正式投诉后再处理，业务会非常被动：</p><ul><li>客户情绪已经升级，处理成本变高。</li><li>风险客户没有被及时识别和分级。</li><li>服务过程缺少可追溯记录，难以复盘责任。</li><li>客服、客诉、业务、合规之间的信息流转不及时。</li><li>历史案例没有转成可复用的风险规则。</li></ul><p>这个项目的目标，是将客诉处理从“事后响应”推进到“事前识别、事中处置、事后复盘”。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>通过 AI 和数据方法识别潜在客诉和外诉风险。</li><li>将公域评论、客户语义、手机号线索、客户信息和服务记录连接起来。</li><li>建立风险场景、关键词、分级规则和处置流程。</li><li>支持客诉团队进行前置安抚、分流处理和结果复盘。</li><li>将历史外诉案例沉淀为可持续迭代的风险识别规则。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我在项目中负责风险场景梳理、语义分析框架、指标链路和产品化表达。这个项目要求我既理解业务流程，也能把非结构化风险信号转成可系统识别的字段和规则。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>场景拆解</td><td>基于历史外诉和业务沟通，拆解退费、服务态度、承诺不符、代维等风险场景</td></tr><tr><td>语义标签</td><td>梳理客户消息中的风险关键词、语义信号和触发条件</td></tr><tr><td>流程设计</td><td>设计风险识别、客户匹配、任务分派、触达安抚和处置复盘链路</td></tr><tr><td>指标体系</td><td>设计采集覆盖、有效线索、客户匹配、触达率、化解率、外诉压降等指标</td></tr><tr><td>系统协同</td><td>与业务、客诉、产品和开发对齐后台流程、企微聊天记录和风控字段</td></tr></tbody></table><h2 id="风险场景体系" tabindex="-1">风险场景体系 <a class="header-anchor" href="#风险场景体系" aria-label="Permalink to &quot;风险场景体系&quot;">​</a></h2><p>资料中基于多月外诉复盘，将风险归纳为多类场景。公开页面不展开具体客户案例，只展示方法层。</p><table tabindex="0"><thead><tr><th>风险场景</th><th>典型信号</th><th>产品化处理</th></tr></thead><tbody><tr><td>退费相关</td><td>多次退费诉求、拖延、拒绝、强烈不满</td><td>标记退费风险，触发专人承接</td></tr><tr><td>服务态度</td><td>长时间未回复、拒接、推诿、态度强硬</td><td>识别服务未覆盖和情绪升级</td></tr><tr><td>承诺不符</td><td>对课程、权益、收益、专属服务产生落差</td><td>关联销售承诺和服务履约记录</td></tr><tr><td>不合格投资者</td><td>高龄、借贷、重大疾病、风险认知不足等</td><td>触发合规风险标签和特殊处理</td></tr><tr><td>投诉意图</td><td>投诉、举报、曝光、监管、媒体等表达</td><td>提升风险等级，进入快速响应</td></tr><tr><td>代维相关</td><td>第三方介入、模板化投诉、账户异常</td><td>识别批量风险和外部操控线索</td></tr><tr><td>服务交接</td><td>员工离职、换人未告知、客户历史断层</td><td>建立交接提醒和服务连续性检查</td></tr></tbody></table><h2 id="关键词与语义识别" tabindex="-1">关键词与语义识别 <a class="header-anchor" href="#关键词与语义识别" aria-label="Permalink to &quot;关键词与语义识别&quot;">​</a></h2><p>项目中沉淀了一套风险词和语义触发规则。例如：</p><table tabindex="0"><thead><tr><th>识别方向</th><th>代表信号</th></tr></thead><tbody><tr><td>投诉升级</td><td>投诉、举报、监管、曝光、媒体、骗子、诈骗</td></tr><tr><td>退费压力</td><td>我要退款、不想做了、什么时候退、一直不处理</td></tr><tr><td>风险认知</td><td>保本、稳赚、不会亏、亏了谁负责</td></tr><tr><td>资金压力</td><td>借钱、贷款、信用卡、急需用钱、医疗费</td></tr><tr><td>特殊人群</td><td>高龄、疾病、家属代管、认知不清</td></tr><tr><td>服务失联</td><td>不回消息、没人管、找不到人、换人没人通知</td></tr></tbody></table><p>这些信号不能单独决定结果，但可以作为风险识别的输入。系统需要结合客户状态、订单、服务记录、聊天上下文和历史处理结果综合判断。</p><h2 id="产品流程" tabindex="-1">产品流程 <a class="header-anchor" href="#产品流程" aria-label="Permalink to &quot;产品流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公域内容 / 企微聊天 / 客户反馈</span></span>
<span class="line"><span>  -&gt; 风险关键词与语义识别</span></span>
<span class="line"><span>  -&gt; 客户身份匹配</span></span>
<span class="line"><span>  -&gt; 风险分级</span></span>
<span class="line"><span>  -&gt; 任务分派与触达</span></span>
<span class="line"><span>  -&gt; 安抚 / 分流 / 处理</span></span>
<span class="line"><span>  -&gt; 结果复盘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>环节</th><th>核心问题</th><th>数据产品设计</th></tr></thead><tbody><tr><td>线索采集</td><td>风险从哪里出现</td><td>公域评论、企微聊天、客户反馈、服务记录</td></tr><tr><td>语义识别</td><td>哪些内容代表风险</td><td>关键词、语义标签、场景分类、风险等级</td></tr><tr><td>客户匹配</td><td>能否定位到内部客户</td><td>手机号、昵称、平台信息、账号映射</td></tr><tr><td>风险分级</td><td>谁需要优先处理</td><td>高风险、中低风险、外诉风险、服务风险</td></tr><tr><td>触达处置</td><td>谁来处理，处理到哪一步</td><td>任务流、承接人、处理状态、结果记录</td></tr><tr><td>复盘优化</td><td>规则是否有效</td><td>化解率、投诉率、触达率、误判漏判复盘</td></tr></tbody></table><h2 id="指标体系" tabindex="-1">指标体系 <a class="header-anchor" href="#指标体系" aria-label="Permalink to &quot;指标体系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标类型</th><th>代表指标</th><th>作用</th></tr></thead><tbody><tr><td>采集指标</td><td>监控账号数、评论数、聊天记录覆盖、有效线索数</td><td>判断风险信号覆盖度</td></tr><tr><td>匹配指标</td><td>手机号提取率、客户匹配率、重复线索合并率</td><td>判断线索能否进入处理流程</td></tr><tr><td>处置指标</td><td>触达率、响应时长、安抚完成率、分流完成率</td><td>判断业务承接效率</td></tr><tr><td>结果指标</td><td>投诉压降、外诉转化、风险化解、复发率</td><td>判断风险识别是否有效</td></tr><tr><td>质量指标</td><td>误判、漏判、规则命中率、人工修正规则</td><td>支持模型和规则迭代</td></tr></tbody></table><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>将客诉风险拆成可识别的场景、关键词、标签和流程。</li><li>基于历史外诉复盘沉淀风险规则，减少对人工经验的单点依赖。</li><li>建立从风险线索到客户匹配、触达、处置和复盘的产品化闭环。</li><li>为 AI 在金融客诉和服务风控中的应用提供可落地框架。</li><li>推动业务从“客户投诉后处理”转向 <span class="text-highlight-warm">提前发现、提前安抚、提前分流</span>。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目体现的是 AI 产品在高风险业务场景中的落地能力。AI 不能只负责“生成回复”，更重要的是把非结构化内容变成风险信号，把风险信号接入业务流程，并能持续复盘识别效果。</p>`,29)])])}const u=d(i,[["render",l]]);export{b as __pageData,u as default};
